class AppError extends Error {
  constructor(message, code) {
    super(message);
    this.name = 'AppError';
    this.code = code;
  }
}

async function submitForm(data) {
  try {
    const result = await postData('/api/submit', data);
    return result;
  } catch (error) {
    if (error instanceof AppError) {
      showUserError(error.message);
    } else {
      logError(error);
      throw error;
    }
  }
}
